function solve(n: number, k: number): number {
    const M = 200;
    let dep: number[] = new Array(M + 1).fill(0);
    dep[1] = 0;

    const popcount = (x: number): number => {
        let count = 0;
        while (x) {
            count += x & 1;
            x = Math.floor(x / 2);
        }
        return count;
    };

    for (let i = 2; i <= M; i++) {
        let cnt = popcount(i);
        dep[i] = 1 + dep[cnt];
    }

    if (k === 0) {
        return 1;
    }

    let S: number[] = [];
    for (let s = 1; s <= M; s++) {
        if (dep[s] === k - 1) {
            S.push(s);
        }
    }

    let total = 0;
    for (let s of S) {
        total += countPopInRange(n, s);
    }

    if (k === 1) {
        total--;
    }

    return total;
}

function countPopInRange(n: number, target: number): number {
    if (target === 0) {
        return 0;
    }
    if (target > 50) {
        return 0;
    }

    let bin = n.toString(2);
    let len = bin.length;
    if (target > len) {
        return 0;
    }

    let arr = bin.split('').map(Number);
    let memo: number[][][] = Array(len);
    for (let i = 0; i < len; i++) {
        memo[i] = Array(target + 1);
        for (let j = 0; j <= target; j++) {
            memo[i][j] = Array(2).fill(-1);
        }
    }

    const dp = (i: number, cnt: number, tight: number): number => {
        if (i === len) {
            if (cnt === target) return 1;
            return 0;
        }
        if (memo[i][cnt][tight] !== -1) {
            return memo[i][cnt][tight];
        }
        let res = 0;
        let up = tight ? arr[i] : 1;
        for (let d = 0; d <= up; d++) {
            let newCnt = cnt;
            if (d === 1) {
                newCnt++;
                if (newCnt > target) {
                    continue;
                }
            }
            let newTight = (tight && (d === up)) ? 1 : 0;
            res += dp(i + 1, newCnt, newTight);
        }
        memo[i][cnt][tight] = res;
        return res;
    };

    return dp(0, 0, 1);
}
