function solve(n: number, k: number): number {
    const depth_arr: number[] = new Array(61).fill(0);
    depth_arr[1] = 0;
    for (let i = 2; i <= 60; i++) {
        let bin = i.toString(2);
        let cnt = 0;
        for (let char of bin) {
            if (char === '1') cnt++;
        }
        depth_arr[i] = 1 + depth_arr[cnt];
    }

    function countNumbersWithOnes(ones: number, n: bigint): bigint {
        if (ones === 0) {
            return n >= 0 ? 1n : 0n;
        }
        if (n < 0) return 0n;
        const binStr = n.toString(2);
        const L = binStr.length;
        const dp: bigint[][][] = Array.from({ length: L + 1 }, () => 
            Array.from({ length: ones + 1 }, () => [0n, 0n])
        );

        dp[0][0][1] = 1n;

        for (let i = 0; i < L; i++) {
            for (let j = 0; j <= ones; j++) {
                for (let tight = 0; tight < 2; tight++) {
                    const cnt = dp[i][j][tight];
                    if (cnt === 0n) continue;
                    const maxDigit = tight ? parseInt(binStr[i]) : 1;
                    for (let d = 0; d <= maxDigit; d++) {
                        const newJ = j + (d === 1 ? 1 : 0);
                        if (newJ > ones) continue;
                        let newTight: number;
                        if (tight) {
                            newTight = (d === maxDigit) ? 1 : 0;
                        } else {
                            newTight = 0;
                        }
                        dp[i + 1][newJ][newTight] += cnt;
                    }
                }
            }
        }
        return dp[L][ones][0] + dp[L][ones][1];
    }

    if (k === 0) {
        return 1;
    } else if (k >= 1 && k <= 5) {
        let total = 0n;
        for (let s = 1; s <= 60; s++) {
            if (depth_arr[s] === k - 1) {
                let count = countNumbersWithOnes(s, BigInt(n));
                if (s === 1) {
                    count = count - 1n;
                }
                total += count;
            }
        }
        return Number(total);
    } else {
        return 0;
    }
}
